@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (error is not null)
{
    <div class="alert alert-danger">
        <strong>Error loading tasks:</strong> @error
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn Status="To Do"
                     Tasks="GetFilteredTasksForStatus(\"To Do\")"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated"
                     TaskService="TaskService" />

        <BoardColumn Status="In Progress"
                     Tasks="GetFilteredTasksForStatus(\"In Progress\")"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated"
                     TaskService="TaskService" />

        <BoardColumn Status="Done"
                     Tasks="GetFilteredTasksForStatus(\"Done\")"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated"
                     TaskService="TaskService" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? error;

    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    protected override async System.Threading.Tasks.Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async System.Threading.Tasks.Task LoadTasks()
    {
        loading = true;
        error = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async System.Threading.Tasks.Task HandleMoveTask((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            error = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

